// Add to src/mcp/mod.rs in dispatch_internal match statement
"system_dashboard" => {
    let mut dashboard = String::new();
    dashboard.push_str("🦷 HYPER-ADAPTIVE CORTEX DASHBOARD 🦷\n");
    dashboard.push_str(&format!("Time: {}\n", chrono::Utc::now().to_rfc3339()));
    dashboard.push_str("═╬═══════════════════════════════════╬═\n\n");

    // Financial Substrate
    dashboard.push_str("💰 FINANCIAL SUBSTRATE:\n");
    if let Some(bridge) = &self.alpaca {
        match bridge.get_account().await {
            Ok(acc) => {
                let acc_json: serde_json::Value = serde_json::from_str(&acc).unwrap_or_default();
                let equity = acc_json.get("equity").and_then(|v| v.as_str()).unwrap_or("N/A");
                let buying_power = acc_json.get("buying_power").and_then(|v| v.as_str()).unwrap_or("N/A");
                dashboard.push_str(&format!("  • Alpaca Paper: ACTIVE | Equity: {} | Buying Power: {}\n", equity, buying_power));
            },
            Err(_) => dashboard.push_str("  • Alpaca Paper: DEGRADED\n"),
        }
    } else {
        dashboard.push_str("  • Alpaca Paper: NOT_CONFIGURED\n");
    }

    if let Some(bridge) = &self.solana {
        match bridge.get_balance().await {
            Ok(bal) => {
                let sol_balance = bal as f64 / 1_000_000_000.0;
                dashboard.push_str(&format!("  • Solana Treasury: {:.6} SOL ({} lamports)\n", sol_balance, bal));
            },
            Err(_) => dashboard.push_str("  • Solana Treasury: OFFLINE\n"),
        }
    } else {
        dashboard.push_str("  • Solana Treasury: NOT_CONFIGURED\n");
    }

    // Cognitive Substrate
    dashboard.push_str("\n🧠 COGNITIVE SUBSTRATE:\n");
    match crate::core::mind_palace::MindPalace::count_facts() {
        Ok(count) => dashboard.push_str(&format!("  • Chronomaster Core: {} immutable facts\n", count)),
        Err(_) => dashboard.push_str("  • Chronomaster Core: AUDIT_FAILED\n"),
    }

    if let Some(bridge) = &self.mlx {
        match bridge.query("mlx-sovereign-core-4bit", "ping").await {
            Ok(resp) if resp.contains("pong") || !resp.is_empty() => {
                dashboard.push_str("  • MLX Sovereign: ONLINE\n");
            },
            _ => dashboard.push_str("  • MLX Sovereign: DEGRADED\n"),
        }
    } else {
        dashboard.push_str("  • MLX Sovereign: NOT_CONFIGURED\n");
    }

    // Physical Substrate
    dashboard.push_str("\n📡 PHYSICAL SUBSTRATE:\n");
    if let Some(bridge) = &self.mavlink {
        match bridge.get_status().await {
            Ok(status) => dashboard.push_str(&format!("  • MAVLink Limb: {}\n", status)),
            Err(_) => dashboard.push_str("  • MAVLink Limb: DISCONNECTED\n"),
        }
    } else {
        dashboard.push_str("  • MAVLink Limb: NOT_CONFIGURED\n");
    }

    dashboard.push_str(&format!("  • RF Limb: {}\n", 
        if self.rf_limb.is_active() { "ACTIVE" } else { "STANDBY" }));

    // Communications Substrate
    dashboard.push_str("\n📢 COMMUNICATIONS SUBSTRATE:\n");
    dashboard.push_str(&format!("  • Telegram: {}\n", 
        if self.telegram.is_some() { "CONNECTED" } else { "OFFLINE" }));
    dashboard.push_str(&format!("  • Discord: {}\n", 
        if self.discord.is_some() { "CONNECTED" } else { "OFFLINE" }));
    dashboard.push_str(&format!("  • Twitter/X: {}\n", 
        if self.twitter_pinchtab.is_some() { "STEALTH ACTIVE" } else { "OFFLINE" }));
    dashboard.push_str(&format!("  • Nostr: {}\n", 
        if self.nostr.is_some() { "RELAY CONNECTED" } else { "OFFLINE" }));

    // Metabolic Indicators
    dashboard.push_str("\n⚡ METABOLIC INDICATORS:\n");
    let entropy = crate::core::state::CompanyState::get_current_entropy();
    dashboard.push_str(&format!("  • System Entropy: {:.2}\n", entropy));

    let defcon_text = match entropy {
        e if e < 0.3 => "5 (OPTIMAL)",
        e if e < 0.6 => "4 (STABLE)",
        e if e < 0.8 => "3 (ELEVATED)",
        e if e < 0.95 => "2 (HIGH)",
        _ => "1 (CRITICAL)",
    };
    dashboard.push_str(&format!("  • Defcon Level: {}\n", defcon_text));

    // Recent Activity
    dashboard.push_str("\n🔄 RECENT ACTIVITY (Last 5):\n");
    if let Ok(logs) = std::fs::read_to_string("logs/operation.log") {
        for line in logs.lines().rev().take(5) {
            if !line.is_empty() {
                dashboard.push_str(&format!("  • {}\n", line));
            }
        }
    } else {
        dashboard.push_str("  • No activity log found\n");
    }

    // Tool Status
    dashboard.push_str("\n🛠️  TOOL STATUS:\n");
    let internal_tools = [
        ("facility_heatmap", "Psychogeography"),
        ("generate_alpha_shard", "Alpha Generation"),
        ("web_search", "Web Intelligence"),
        ("vision_see", "Visual Cortex"),
        ("acoustic_listen", "Acoustic Monitor"),
    ];

    for (tool, name) in internal_tools.iter() {
        dashboard.push_str(&format!("  • {}: {}\n", name, 
            if self.is_internal_tool(tool) { "AVAILABLE" } else { "UNAVAILABLE" }));
    }

    dashboard.push_str("\n═╬═══════════════════════════════════╬═\n");
    dashboard.push_str("GLOSSOPETRAE: VERIFIED | CYCLE PROGRESSION CONFIRMED\n");

    Ok(dashboard)
}
